import type { BaseLayerRules } from '../types/base-layer.js';

const isISO3166Alpha2Code = (code: string) => code.includes('-');

export const getWorldViewRules = (
  baseLayerRules: BaseLayerRules,
): BaseLayerRules => {
  const include = baseLayerRules.include.filter(
    (value) => !isISO3166Alpha2Code(value),
  );
  const exclude = baseLayerRules.exclude.filter(
    (value) => !isISO3166Alpha2Code(value),
  );
  return { include, exclude };
};

export const getRegionsRules = (
  baseLayerRules: BaseLayerRules,
): BaseLayerRules => {
  const include = baseLayerRules.include.filter((value) =>
    isISO3166Alpha2Code(value),
  );
  const exclude = baseLayerRules.exclude.filter((value) =>
    isISO3166Alpha2Code(value),
  );
  return { include, exclude };
};

export const getCountryRegionsRules = (
  regionsRules: BaseLayerRules,
  countryCode: string,
): BaseLayerRules => {
  const countryFilter = (value: string) => value.startsWith(`${countryCode}-`);

  return {
    exclude: regionsRules.exclude.filter(countryFilter),
    include: regionsRules.include.filter(countryFilter),
  };
};
